9MwglY1TdOrz3H_9t5bHueBQmyWE", "peopleAlsoViewed/22/public_identifier": "pamelaongcg", "peopleAlsoViewed/22/url": "https://linkedin.com/in/ACoAAAZrcrgBQGez2TlZOFMepfCBb5wc4dK33F4", "peopleAlsoViewed/23/entity_urn": "urn:li:fsd_profile:ACoAAC1ZPR4BwuzTCxNCfT8y9_4h3Bh5Z9omopc", "peopleAlsoViewed/23/first_name": "Jirapinya ", "peopleAlsoViewed/23/follower_count": "60", "peopleAlsoViewed/23/headline": "I have been working in the hospitality industry for over five years where I have developed and honed customer service and management skills.", "peopleAlsoViewed/23/last_name": "Boonchaui ", "peopleAlsoViewed/23/premium": "false", "peopleAlsoViewed/23/profile_picture": "https://media.licdn.com/dms/image/v2/D5603AQFedzNO5x3hAQ/profile-displayphoto-shrink_800_800/B56ZYCNl.WGsAg-/0/1743793841048?e=1778112000&v=beta&t=YQ4Yfcs35wMyMA-yXwAp9Ob9PGszBtD6Ff_7RI3Lpn4", "peopleAlsoViewed/23/public_identifier": "jirapinya-boonchaui-16696b192", "peopleAlsoViewed/23/url": "https://linkedin.com/in/ACoAAC1ZPR4BwuzTCxNCfT8y9_4h3Bh5Z9omopc", "peopleAlsoViewed/24/entity_urn": "urn:li:fsd_profile:ACoAADGEMEoBEpqU38uvDnXFEndrjBlMKKGm85M", "peopleAlsoViewed/24/first_name": "Pongsakon", "peopleAlsoViewed/24/follower_count": "373", "peopleAlsoViewed/24/headline": "Chief Concierge ,Concierge, Les Clefs d’Or Thailand", "peopleAlsoViewed/24/last_name": "Prasertthongkon", "peopleAlsoViewed/24/premium": "false", "peopleAlsoViewed/24/profile_picture": "https://media.licdn.com/dms/image/v2/D5603AQFOdyJmxSHibg/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1690342035180?e=1778112000&v=beta&t=XfARYvKM0fI6i--fAlZFAqCmzyiWxzxb5dMRN0Cm1_0", "peopleAlsoViewed/24/public_identifier": "pongsakon-prasertthongkon-2362701b2", "peopleAlsoViewed/24/url": "https://linkedin.com/in/ACoAADGEMEoBEpqU38uvDnXFEndrjBlMKKGm85M", "peopleAlsoViewed/25/entity_urn": "urn:li:fsd_profile:ACoAAA3YwksBDhqdc-Iol7lD38eAjwEJvSCxRo4", "peopleAlsoViewed/25/first_name": "Fabio", "peopleAlsoViewed/25/follower_count": "556", "peopleAlsoViewed/25/headline": "Executive chef", "peopleAlsoViewed/25/last_name": "Genghini", "peopleAlsoViewed/25/premium": "false", "peopleAlsoViewed/25/public_identifier": "fabio-genghini-32397265", "peopleAlsoViewed/25/url": "https://linkedin.com/in/ACoAAA3YwksBDhqdc-Iol7lD38eAjwEJvSCxRo4", "profilePic": "https://media.licdn.com/dms/image/v2/D5603AQHPh7aJ1GcZrw/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1681102810428?e=1778112000&v=beta&t=GT77N_5sTP_6vo2H6yKyC3rYkOYK5VuOMxkUTwF0mNA", "profilePicHighQuality": "https://media.licdn.com/dms/image/v2/D5603AQHPh7aJ1GcZrw/profile-displayphoto-shrink_800_800/profile-displayphoto-shrink_800_800/0/1681102810428?e=1778112000&v=beta&t=GT77N_5sTP_6vo2H6yKyC3rYkOYK5VuOMxkUTwF0mNA", "publicIdentifier": "devdasgupta", "recommendations/0/context": "Debdyuti (Dev) managed Peerapon directly", "recommendations/0/date": "November 1, 2025", "recommendations/0/description": "It is with genuine pleasure and without reservation that I recommend Khun Mark, whom I had the privilege of working alongside during their tenure as the Director, Human Resources at Courtyard by Marriott Bangkok. Khun Mark served in this critical leadership role for approximately six and a half years (6.5 years), leaving an undeniable mark of excellence on the hotel’s operations and culture.\n\nDuring their extensive tenure, Khun Mark demonstrated exceptional leadership, strategic foresight, and an unwavering commitment to both corporate mandates and employee well-being. Khun Mark spearheaded the successful implementation of the Marriott Thailand Voyager Program and managed the logistics and execution of large-scale events, including the annual Marriott Thailand Sport Days. \n\nPerhaps their most significant achievement was in the realm of operational efficiency and talent retention. Khun Mark masterfully managed all HR operations, successfully reducing staff turnover despite the challenging constraint of a limited operational budget. This accomplishment speaks volumes about his innovative problem-solving skills, his ability to negotiate effectively, and his capacity to cultivate a positive and engaging work environment that prioritized employee satisfaction using minimal resources. \n\nKhun Mark is a dedicated, People and Results-oriented, and fiscally responsible HR leader. Any organization seeking a person who can drive strategic projects, manage resources judiciously, and profoundly impact employee engagement and retention would be fortunate to have his on their team.", "recommendations/0/name": "Peerapon Kuakomoldej", "recommendations/0/subtitle": "Vice President, Human Resources and Brand Culture", "recommendations/0/url": "https://www.linkedin.com/in/peerapon-kuakomoldej-8020b0a3/", "recommendations/0/urn": "urn:li:fsd_profile:ACoAABXnr4IBNYCtVCf5azkDuDQkHF9KgWESC2w", "recommendations/1/context": "Debdyuti (Dev) was senior to Sarah but didn't manage Sarah directly", "recommendations/1/date": "May 21, 2018", "recommendations/1/description": "I have been knowing Sarah for the past 8 years now. We have worked together in Dubai while I was in the role of Cluster Director of Finance with Mövenpick Hotels and Resorts International. One of the hotel in the cluster was Mövenpick Hotel Deira where Sarah joined in the pre-opening team as the Communication Manager. I was amazed to see her energy, attention to details and pro-activeness in executing the pre-opening marketing plan, positioning the property and branding the outlets. Later she was promoted as the Director of Communication for Mövenpick Hotel, Ibn Battuta Gate, under the same cluster. During this time, I came to know her more closely as a colleague and was impressed with her professionalism. It was then a very difficult time and the property needed to be repositioned to generate adequate revenue and return to the investor. Sarah did a remarkable job in repositioning the property in terms of marketing, communication and PR. She formed a small team of 3 person and effectively guided them in executing one project after another. Her contribution in re-branding six of the signature restaurants of the hotel and positioning the restaurant in a highly competitive market was commendable. Sarah is highly creative, but at the time what impressed me the most is her business acumen. During the difficult business situation, she would always come prepared with a business case analysis and return on investment calculation for each of her marketing initiative and was able to convince me of her action and vis-à-vis result. It was an absolute pleasure for me to work with her and I will be glad to work with her again in the future.  ", "recommendations/1/name": "Sarah Fernandez Bokhari", "recommendations/1/subtitle": "General Manager PR & Communications", "recommendations/1/url": "https://www.linkedin.com/in/sarahfernandez18/", "recommendations/1/urn": "urn:li:fsd_profile:ACoAAAQshtMB607nKtIMvYSDut8WLleXiof81-M", "recommendations/2/context": "Debdyuti (Dev) was senior to Elena but didn't manage Elena directly", "recommendations/2/date": "March 15, 2013", "recommendations/2/description": "I worked with Elena for a short period at the MPIBG. What I have seen her during that period as very hard working and dedicated. The hotel was at that time trying very hard to position in the market and gain the fair market share and she was put to face that challange. She worked deligenty towards meeting that challange. She was a very pleasant colleague and I enjoyed working with her.", "recommendations/2/name": "Elena Chentsova-Rietmann", "recommendations/2/subtitle": "Distribution Operations Manager at Jumeirah Hotels & Resorts", "recommendations/2/url": "https://www.linkedin.com/in/echentsy/", "recommendations/2/urn": "urn:li:fsd_profile:ACoAAACpxGIBZPMTmG2h7Bk8gqZ08io5krr0CKY", "recommendations/3/context": "Debdyuti (Dev) managed Kapil directly", "recommendations/3/date": "March 15, 2011", "recommendations/3/description": "Kapil joined me at the Moevenpick Resort & Spa as the Asst. FC coming completely from a non hotel industry background. His strength at that time was good technical knowledge of his subject, bubbling with positive energy and an intense drive to perform which eventually led me to offer him the job. Within a period of 6 months he understood the hotel business and his role in the given situation. MP Mauritius being a difficult operation to run he showed excellent business acumen to lead the team to the company goal. He is self driven and has an inexhaustible appetite to learn new things in the field of his operation. I am proud to have worked with him wish him all the success in future.", "recommendations/3/name": "Kapil Rastogi", "recommendations/3/subtitle": "Director of Finance at Hyatt Regency Chennai, india", "recommendations/3/url": "https://www.linkedin.com/in/kapil-rastogi-22a4b621/", "recommendations/3/urn": "urn:li:fsd_profile:ACoAAASF5MIBgNqCSMR9FGS9_K_1qCWruAVwlUk", "recommendations/4/context": "Debdyuti (Dev) worked with Joel on the same team", "recommendations/4/date": "January 20, 2011", "recommendations/4/description": "I worked with Joel in Dar es Salaam at the Royal Plam Hotel where he was the F&B Manager. He is a very energetic person and always in a mission. He takes up project one after another and just finishes them, an extremely result oriented guy. He can think out of box and very creative with ideas and always known to be coming up with new ideas. He is a very freind and jolly character and nothing was stressful for him. He enjoyed his work and made people around him also happy. I really enjoyed working with him, he was a good friend too.", "recommendations/4/name": "Joel P.", "recommendations/4/subtitle": "Divisional Operations Manager at Legacy Hotels & Resorts | Operational Excellence", "recommendations/4/url": "https://www.linkedin.com/in/joel-p-22946b18/", "recommendations/4/urn": "urn:li:fsd_profile:ACoAAAOgoYEBq1jMhSD9NTPbjvZT6S8foV__pKA", "recommendations/5/context": "Debdyuti (Dev) managed Kaushik directly", "recommendations/5/date": "May 12, 2010", "recommendations/5/description": "When Kaushik joined me at Royal Palm Hotel in Dar es Salaam he was a freshly qualified chartered accountant but not having any experience in hotel industry but due to his deligence, hard work and being very strong technically picked up the knowledge of hotel industry very quickly and efficiently. Within a short while he took over the entire responsibility of the day to day accounting, finalization of monthly accounts, reconciliation of GL. He was instrumental in developing a very strong internal control system as well in the hotel. He worked with me almost 4 years and during this period he had been an asset to the company and jis contribution to the company was noteworthy.", "recommendations/5/name": "Kaushik Ghosh, ACA", "recommendations/5/subtitle": "Director of Finance - Hotels, Luxury & Lifestyle", "recommendations/5/url": "https://www.linkedin.com/in/kaushik-ghosh-aca-134b6b7/", "recommendations/5/urn": "urn:li:fsd_profile:ACoAAAFq5PgB8w296l2rRLKJRPofL0jJGEnexL8", "recommendations/6/context": "Debdyuti (Dev) worked with Régis on the same team", "recommendations/6/date": "September 5, 2009", "recommendations/6/description": "I have worked with Regis for one year in Jordan when he was the Director of Revenue Management for Jordan cluster. He is very analytical and has the ability to breakdown a bundle of information in meaningful parts with great ease. In his tenure with Moevenpick Jordan he helped us by training the reservation team how important it is to capture the primary data accurately explainig that how those data helps us in taking stategic decisions. He also helped in bringing a defined structure in the hotel system and cleaned the database for meaningful use. He always challanged decisions that are not based on facts and concluded without analysis of available information. He is a precisionist and gives attention to details although sometimes he may sound very theoritical. I thoroughly enjoyed working with him and wish him all the best in his future endeavors.", "recommendations/6/name": "Régis Kahn", "recommendations/6/subtitle": "EHLeague - Exclusive luxury for the discerning traveler", "recommendations/6/url": "https://www.linkedin.com/in/regilait/", "recommendations/6/urn": "urn:li:fsd_profile:ACoAAAI9-2QBEnfcLAt6vMMqULY-T4HyZrzpzDs", "recommendationsReceived/0/context": "Kapil reported directly to Debdyuti (Dev)", "recommendationsReceived/0/date": "March 7, 2011", "recommendationsReceived/0/description": "I have worked with Mr. Dev only for 6 months and in this period I came to know him as highly organised person having in depth knowledge of the area of his work. He has mastered the leadership skill and knows how to get the work done in most efficient way with the mutual interest of the company and the employees. His management skills were highly appreciated and were very practical and based on strong believes. I would like to wish him all the best for his future and Thank him for his support.", "recommendationsReceived/0/name": "Kapil Rastogi", "recommendationsReceived/0/subtitle": "Director of Finance at Hyatt Regency Chennai, india", "recommendationsReceived/0/url": "https://www.linkedin.com/in/kapil-rastogi-22a4b621/", "recommendationsReceived/0/urn": "urn:li:fsd_profile:ACoAAASF5MIBgNqCSMR9FGS9_K_1qCWruAVwlUk", "recommendationsReceived/1/context": "Thomas was senior to Debdyuti (Dev) but didn't manage Debdyuti (Dev) directly", "recommendationsReceived/1/date": "October 23, 2010", "recommendationsReceived/1/description": "I worked with Dev in the early 2000's when he was the financial controller at the Royal Palm Hotel and Dev was very well equipped in technical accounting skills, management of staff, projects and his own time. Dev's knowledge of the hospitality industry was superb and this in conjunction with his good business sense he was a financial controller and added great value in directing the business activities and direction of his unit. A real value adder to the organisation and the bigger operational structure.", "recommendationsReceived/1/name": "Thomas Klingler", "recommendationsReceived/1/subtitle": "Financial Director - MetCon SA", "recommendationsReceived/1/url": "https://www.linkedin.com/in/thomas-klingler-a6842211/", "recommendationsReceived/1/urn": "urn:li:fsd_profile:ACoAAAJgNXABt0btknxQEcuLqYMSFDxpX2Wlxhw", "recommendationsReceived/2/context": "Kaushik reported directly to Debdyuti (Dev)", "recommendationsReceived/2/date": "November 22, 2009", "recommendationsReceived/2/description": "I have worked with Dev for almost 4.5 years during our tenure in Dar Es Salaam. Working under the guidance of Dev has been one of the most memorable experiences as his qualities of Financial Prudence, Value Creation, Decision making and Team Management are of very high standards. A thorough professional, as he is known by all, it will be a pleasure working with him again.", "recommendationsReceived/2/name": "Kaushik Ghosh, ACA", "recommendationsReceived/2/subtitle": "Director of Finance - Hotels, Luxury & Lifestyle", "recommendationsReceived/2/url": "https://www.linkedin.com/in/kaushik-ghosh-aca-134b6b7/", "recommendationsReceived/2/urn": "urn:li:fsd_profile:ACoAAAFq5PgB8w296l2rRLKJRPofL0jJGEnexL8", "recommendationsReceived/3/context": "Régis worked with Debdyuti (Dev) on the same team", "recommendationsReceived/3/date": "November 18, 2009", "recommendationsReceived/3/description": "I experienced Dev as a financial expert who was always focused on value creation and cost optimization. He always made sure that all activities were aligned to the Strategy and Financial Goals of both Mövenpick Hotels & Resorts and our owner. He was leveraging relationships to the maximum, and was providing high quality results translated through very competitive result in the P&L.", "recommendationsReceived/3/name": "Régis Kahn", "recommendationsReceived/3/subtitle": "EHLeague - Exclusive luxury for the discerning traveler", "recommendationsReceived/3/url": "https://www.linkedin.com/in/regilait/", "recommendationsReceived/3/urn": "urn:li:fsd_profile:ACoAAAI9-2QBEnfcLAt6vMMqULY-T4HyZrzpzDs", "recommendationsReceived/4/context": "Chris worked with Debdyuti (Dev) on the same team", "recommendationsReceived/4/date": "November 10, 2009", "recommendationsReceived/4/description": "I had the opportunity to meet Dev during my Interim Assignment in Dar-es-Salaam, Tanzania. Dev has excellent knowledge in the Accounting and IT environments and was of great help in successfully completeing the assignment.Dev was respected and admired by all his superiors and colleauges. I would be pleased to work with Dev again.", "recommendationsReceived/4/name": "Chris Isaac", "recommendationsReceived/4/subtitle": "Consultant & Interim Manager", "recommendationsReceived/4/url": "https://www.linkedin.com/in/chrisisaacgermany/", "recommendationsReceived/4/urn": "urn:li:fsd_profile:ACoAAAChfHcBuCaTsc1KaHddvCRpeWta2C1Sq4o", "recommendationsReceived/5/context": "Debdyuti (Dev) was Parag's client", "recommendationsReceived/5/date": "November 10, 2009", "recommendationsReceived/5/description": "I have known Dev as a task master and a tough negotiator in his role at Royal Palm Hotel (Under Legacy & Moevenpick management) at Dar Es Salaam. He has been fair and transparent by providing opportunity to the vendors and managing to extract the best for his organisation. He is amongst the rare breed of people who can successfully manage personal and professional relationship without mixing the two. People like him are destined for success in their career and I wish him well.", "recommendationsReceived/5/name": "Parag Mendiratta", "recommendationsReceived/5/subtitle": "Driving energy transition & innovation across Eastern Africa | Empowering local talent with global expertise", "recommendationsReceived/5/url": "https://www.linkedin.com/in/parag-mendiratta/", "recommendationsReceived/5/urn": "urn:li:fsd_profile:ACoAAAF9R3wBOS9QmD9i1Sdq2G94StvP7FhnGwo", "skills/0/title": "Budgets", "skills/1/title": "Hotels", "skills/2/title": "Pre-opening", "skills/3/title": "Resorts", "skills/4/title": "Managerial Finance", "skills/5/title": "Hospitality Industry", "skills/6/title": "Strategy", "skills/7/title": "Management", "skills/8/title": "Accounting", "skills/9/title": "Leadership", "skills/10/title": "CRM", "skills/11/title": "Internal Controls", "skills/12/title": "Start-ups", "skills/13/title": "Auditing", "skills/14/title": "Team Management", "skills/15/title": "Strategic Financial Planning", "skills/16/title": "Finance", "skills/17/title": "ERP", "skills/18/title": "Financial Accounting", "skills/19/title": "Income Statement", "totalExperienceYears": "28.2", "totalRecommendationsGiven": "7", "totalRecommendationsReceived": "6", "urn": "ACoAAAFVt-kB4gPm0c4Nl_dxyrUao9vY4j57djk"}$$::jsonb),
